={{ (() => {
  try {
    const payload = $('Recibir WhatsApp').item.json.body;

    // Busca la información del anuncio en la ruta nueva O en la ruta vieja
    let ctx = payload?.data?.contextInfo || payload?.data?.message?.extendedTextMessage?.contextInfo;

    if (ctx) {
      const ad = ctx.externalAdReply || ctx.adReply;

      // Unimos todos los datos posibles (URLs, tipo de conversión, tipo de fuente) para analizarlos
      let sourceStr = (ctx.conversionSource || '') + ' ' + 
                      (ad?.sourceUrl || '') + ' ' + 
                      (ad?.mediaUrl || '') + ' ' + 
                      (ad?.sourceType || '');
      sourceStr = sourceStr.toUpperCase();

      // Detectamos si menciona Instagram por algún lado
      if (sourceStr.includes('INSTAGRAM') || sourceStr.includes('IG_ADS')) {
        return 'Instagram Ads';
      }
      // Detectamos si menciona Facebook (como en tu JSON que tiene el reel de facebook.com)
      if (sourceStr.includes('FACEBOOK') || sourceStr.includes('FB_ADS') || sourceStr.includes('FB.COM')) {
        return 'Facebook Ads';
      }

      // Si sabemos que es anuncio pero Meta no especifica la red social
      if (ad || ctx.conversionSource) {
        return 'Anuncio (Meta)';
      }
    }
  } catch(e) {}

  // Si no encontró nada de publicidad en ninguna ruta, es Orgánico
  return 'Orgánico';
